"use strict";(self.webpackChunkblogv2_dev=self.webpackChunkblogv2_dev||[]).push([[8322],{3017:(e,s,n)=>{n.r(s),n.d(s,{data:()=>a});const a={key:"v-369ba352",path:"/blogs/Tools/git.html",title:"Git",lang:"zh-CN",frontmatter:{title:"Git",Date:"2020-05-14T00:00:00.000Z",tag:["git"],category:["Tools"],summary:"Git GitHub Host 加速 下载软件：SwitchHosts 添加一条规则： SwitchHosts Rule 方案名：GitHub（可以自行命名） 类型：远程 URL 地址： 自动更新：1个小时 SSH Server Clone form server file using SSH: Connect using ssh: ssh key: rep",head:[["meta",{property:"og:url",content:"https://vueblog.weigao.cc/blogs/Tools/git.html"}],["meta",{property:"og:site_name",content:"WW"}],["meta",{property:"og:title",content:"Git"}],["meta",{property:"og:type",content:"article"}],["meta",{property:"og:updated_time",content:"2022-05-06T08:47:53.000Z"}],["meta",{property:"og:locale",content:"zh-CN"}],["meta",{property:"article:tag",content:"git"}],["meta",{property:"article:modified_time",content:"2022-05-06T08:47:53.000Z"}]]},excerpt:"",headers:[{level:2,title:"GitHub Host 加速",slug:"github-host-加速",children:[]},{level:2,title:"SSH Server",slug:"ssh-server",children:[]},{level:2,title:"repo",slug:"repo",children:[{level:3,title:"Workflow Usage",slug:"workflow-usage",children:[]},{level:3,title:"repo init",slug:"repo-init",children:[]}]},{level:2,title:"Git Reset",slug:"git-reset",children:[{level:3,title:"删除新增文件",slug:"删除新增文件",children:[]}]},{level:2,title:"Git Config",slug:"git-config",children:[]},{level:2,title:"GitHub Accelerate",slug:"github-accelerate",children:[]},{level:2,title:"Git Clone",slug:"git-clone",children:[]},{level:2,title:"Tag",slug:"tag",children:[]},{level:2,title:"Status",slug:"status",children:[]},{level:2,title:".gitignore",slug:"gitignore",children:[]},{level:2,title:"Differ",slug:"differ",children:[]},{level:2,title:"Remote",slug:"remote",children:[]},{level:2,title:"Git 别名",slug:"git-别名",children:[]},{level:2,title:"Git Branch",slug:"git-branch",children:[{level:3,title:"分支管理",slug:"分支管理",children:[]}]},{level:2,title:"Reference",slug:"reference",children:[]}],git:{createdTime:1644237761e3,updatedTime:1651826873e3,contributors:[{name:"chenweigao",email:"297859260@qq.com",commits:3},{name:"weigao chen",email:"weigao_1995@yeah.net",commits:2},{name:"chenweigao",email:"chenweigao1@huawei.com",commits:1}]},readingTime:{minutes:7.97,words:2392},filePathRelative:"blogs/Tools/git.md"}},9783:(e,s,n)=>{n.r(s),n.d(s,{default:()=>z});var a=n(6252);const i=(0,a._)("h1",{id:"git",tabindex:"-1"},[(0,a._)("a",{class:"header-anchor",href:"#git","aria-hidden":"true"},"#"),(0,a.Uk)(" Git")],-1),t=(0,a._)("h2",{id:"github-host-加速",tabindex:"-1"},[(0,a._)("a",{class:"header-anchor",href:"#github-host-加速","aria-hidden":"true"},"#"),(0,a.Uk)(" GitHub Host 加速")],-1),l=(0,a.Uk)("下载软件："),d={href:"https://github.com/oldj/SwitchHosts/releases",target:"_blank",rel:"noopener noreferrer"},c=(0,a.Uk)("SwitchHosts"),r=(0,a._)("p",null,"添加一条规则：",-1),o={class:"custom-container tip"},p=(0,a._)("p",{class:"custom-container-title"},"SwitchHosts Rule",-1),u=(0,a._)("p",null,"方案名：GitHub（可以自行命名）",-1),g=(0,a._)("p",null,"类型：远程",-1),h=(0,a.Uk)("URL 地址："),v={href:"https://cdn.jsdelivr.net/gh/ineo6/hosts/hosts",target:"_blank",rel:"noopener noreferrer"},m=(0,a.Uk)("https://cdn.jsdelivr.net/gh/ineo6/hosts/hosts"),b=(0,a._)("p",null,"自动更新：1个小时",-1),f=(0,a.uE)('<h2 id="ssh-server" tabindex="-1"><a class="header-anchor" href="#ssh-server" aria-hidden="true">#</a> SSH Server</h2><p>Clone form server file using SSH:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> clone ssh://root@120.78.71.220:22/~/data\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Connect using ssh:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">ssh</span> root@174.137.62.75\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>ssh key:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>ssh-keygen\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="repo" tabindex="-1"><a class="header-anchor" href="#repo" aria-hidden="true">#</a> repo</h2><h3 id="workflow-usage" tabindex="-1"><a class="header-anchor" href="#workflow-usage" aria-hidden="true">#</a> Workflow Usage</h3><p>repo 的工作流可以参考这个文档(注意有中文版，可以切换语言查看)<sup class="footnote-ref"><a href="#footnote1">[1]</a><a class="footnote-anchor" id="footnote-ref1"></a></sup>，其流程大概可以总结为以下步骤：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>repo start\n<span class="token function">git</span> <span class="token function">add</span> <span class="token builtin class-name">.</span>\n<span class="token function">git</span> commit <span class="token builtin class-name">.</span>\nrepo upload\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中几个 repo 专有的命令如下表格所示[^2]：</p><table><thead><tr><th>command</th><th>description</th><th>example</th></tr></thead><tbody><tr><td>repo init</td><td>Initializes a new client.</td><td></td></tr><tr><td>repo sync</td><td>Syncs the client to the repositories.</td><td></td></tr><tr><td>repo start</td><td>Starts a new branch.</td><td></td></tr><tr><td>repo status</td><td>Shows the status of the current branch.</td><td></td></tr><tr><td>repo upload</td><td>Uploads changes to the review server.</td><td></td></tr></tbody></table><p>以下是使用的例子（简单的 workflow, 后文会详细研究每一个命令）：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>repo <span class="token function">sync</span> PROJECT0 PROJECT1 <span class="token punctuation">..</span>. PROJECTN\nrepo start BRANCH_NAME <span class="token builtin class-name">.</span>\nrepo status <span class="token builtin class-name">.</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果我们要给特定的项目创建分支，则：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>repo start BRANCH_NAME PROJECT_NAME\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>切换分支还是使用 <code>checkout</code> 命令，但是查看分支可以使用</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> branch\nrepo branches\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>如果要查看修改，则使用：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>repo <span class="token function">diff</span>\n\n<span class="token comment"># or</span>\n<span class="token builtin class-name">cd</span> ~/WORKING_DIRECTORY/PROJECT\n<span class="token function">git</span> <span class="token function">diff</span> --cached\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>修改完后，我们同步最新改动并提交我们的改动：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>repo <span class="token function">sync</span>\nrepo upload\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="repo-init" tabindex="-1"><a class="header-anchor" href="#repo-init" aria-hidden="true">#</a> repo init</h3><p>我们需要一个 xml 文件来制定 init 的，一般而言这个 xml 文件在远程，可以使用 <code>-u</code> 参数进行指定，官方对此的使用说明如下：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>repo init -u url <span class="token punctuation">[</span>options<span class="token punctuation">]</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在当前目录中安装 Repo。这样会创建一个 <code>.repo/</code> 目录，其中包含存放 Repo 源代码和标准 Android 清单文件的 Git 代码库。</p><p>如果我们要重新 init, 则删除这个 <code>.repo/</code> 目录即可。</p><p>需要注意的是，这个 <code>.repo/</code> 目录是影响到所有得子目录的，这个和 git 的原理类似。</p><p>选项：</p><ul><li><code>-u</code>: 指定从中检索清单代码库的网址。常见清单位于 <code>https://android.googlesource.com/platform/manifest</code>。</li><li><code>-m</code>: 选择代码库中的清单文件。如果未选择清单名称，则默认为 <code>default.xml</code>。</li><li><code>-b</code>：指定修订版本，即特定的 manifest-branch。</li></ul><div class="custom-container tip"><p class="custom-container-title">提示</p><p><strong>注意</strong>：对于所有剩余的 Repo 命令，当前的工作目录必须是 <code>.repo/</code> 的父目录或该父目录的子目录。</p></div><h2 id="git-reset" tabindex="-1"><a class="header-anchor" href="#git-reset" aria-hidden="true">#</a> Git Reset</h2><p>在某次提交后如果发现自己忘记添加某些文件，或者写错了提交信息，可以使用<code>--amend</code>选项</p><p>一个使用 --amend 的例子：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> commit -m <span class="token string">&quot;initial commit&quot;</span>\n<span class="token function">git</span> <span class="token function">add</span> forgotten_file\n<span class="token function">git</span> commit --amend\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>撤销已暂存的文件</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> reset HEAD reset.md\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>舍弃对文件的修改</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> checkout -- <span class="token operator">&lt;</span>filename<span class="token operator">&gt;</span>\n<span class="token function">git</span> checkout -- <span class="token builtin class-name">.</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>！但是要主要到，<code>git checkout</code>是一条非常危险的命令，执行该命令以后，任何对文件作出的修改都会丢失，因为上述命令用之前版本的文件做了覆盖。</p><p>回到远程仓库的状态</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> fetch --all <span class="token operator">&amp;&amp;</span> <span class="token function">git</span> rest --hard origin/master\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>放弃所有更改</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> checkout <span class="token builtin class-name">.</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="删除新增文件" tabindex="-1"><a class="header-anchor" href="#删除新增文件" aria-hidden="true">#</a> 删除新增文件</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> clean -xdff\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>注意这个是把新增的未保存到缓冲区的文件给删除掉</p><p>如果是改动过的，就继续使用 <code>git checkout – .</code> 就可以了。</p><h2 id="git-config" tabindex="-1"><a class="header-anchor" href="#git-config" aria-hidden="true">#</a> Git Config</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> config --global user.name <span class="token operator">&lt;</span>username<span class="token operator">&gt;</span>\n<span class="token function">git</span> config --global user.email <span class="token operator">&lt;</span>useremail<span class="token operator">&gt;</span>\n<span class="token function">git</span> config --global core.editor emacs\n\n<span class="token function">git</span> config --list\n<span class="token function">git</span> config user.name\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> <span class="token builtin class-name">help</span> <span class="token operator">&lt;</span>verb<span class="token operator">&gt;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>cache the config:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> config --global credential.helper cache\n<span class="token function">git</span> config --global credential.helper store\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>如果遇到了 443 的问题，则可以重置 git 的配置：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> config --global credential.helper store\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="github-accelerate" tabindex="-1"><a class="header-anchor" href="#github-accelerate" aria-hidden="true">#</a> GitHub Accelerate</h2>',57),k=(0,a._)("li",null,[(0,a._)("p",null,[(0,a.Uk)("Update the host in "),(0,a._)("code",null,"C:\\Windows\\System32\\drivers\\etc")])],-1),x=(0,a.Uk)("Visit  "),_={href:"http://tool.chinaz.com/dns",target:"_blank",rel:"noopener noreferrer"},w=(0,a.Uk)("http://tool.chinaz.com/dns"),G=(0,a._)("li",null,[(0,a._)("p",null,"Found the IP and update hosts as the follow example:")],-1),R=(0,a.uE)('<div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token number">13.250</span>.177.223 github.com\n<span class="token number">151.101</span>.228.133 assets-cdn.github.com\n<span class="token number">151.101</span>.73.194 github.global.ssl.fastly.net\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="git-clone" tabindex="-1"><a class="header-anchor" href="#git-clone" aria-hidden="true">#</a> Git Clone</h2><p>克隆较慢时使用：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> clone --depth<span class="token operator">=</span><span class="token number">1</span> ulr\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="tag" tabindex="-1"><a class="header-anchor" href="#tag" aria-hidden="true">#</a> Tag</h2><p>show tag:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> tag\n<span class="token function">git</span> tag -l\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>add tag:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> tag -a v1.0 -m <span class="token string">&quot;my first version&quot;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>push tags to origin:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> push origin v1.0\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>强制推送使用：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> push -f origin branch_name\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="status" tabindex="-1"><a class="header-anchor" href="#status" aria-hidden="true">#</a> Status</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> status\n<span class="token function">git</span> status -s\n<span class="token comment"># ??: untrack</span>\n<span class="token comment"># M : Modified</span>\n<span class="token comment"># A : Modified new file</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="gitignore" tabindex="-1"><a class="header-anchor" href="#gitignore" aria-hidden="true">#</a> .gitignore</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">cat</span> .gitignore\n*.<span class="token punctuation">[</span>oa<span class="token punctuation">]</span>\n*~\n\n<span class="token comment">#Example</span>\n*.a\n<span class="token operator">!</span>lib.a <span class="token comment"># 仍然跟踪 lib.a, 即使上一行指令要忽略</span>\n/TODO <span class="token comment"># 忽略当前目录的 todo 文件</span>\nbuild/ <span class="token comment"># 忽略 build/ 目录下的所有文件</span>\ndoc/*.txt <span class="token comment"># 忽略 doc/notes.txt, 而不忽略 doc/server/arch.txt</span>\ndoc/**/*.pdf <span class="token comment"># 忽略 doc/ 目录下的所有.pdf文件</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果改动文件不生效的话，使用：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> <span class="token function">rm</span> -r --cached <span class="token builtin class-name">.</span>\n<span class="token function">git</span> <span class="token function">add</span> <span class="token builtin class-name">.</span>\n<span class="token function">git</span> commit -m <span class="token string">&#39;update .gitignore&#39;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>',19),y=(0,a.Uk)("除此之外，还可以参考"),H={href:"https://github.com/github/gitignore",target:"_blank",rel:"noopener noreferrer"},E=(0,a.Uk)("GitHub官方示例"),S=(0,a.uE)('<h2 id="differ" tabindex="-1"><a class="header-anchor" href="#differ" aria-hidden="true">#</a> Differ</h2><p>如果想知道具体的变更内容，而不像 <code>git status</code> 那么宽泛，可以使用 <code>git diff</code></p><p>查看有哪些已暂存的内容会进入下一次提交，该命令将暂存的变更与上一次提交的内容相比较:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> <span class="token function">diff</span> --staged\n<span class="token function">git</span> <span class="token function">diff</span> --cached\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>如果要把文件保存在工作目录，但从暂存区移除该文件:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">rm</span> <span class="token operator">&lt;</span>filename<span class="token operator">&gt;</span>\n<span class="token function">git</span> <span class="token function">rm</span> --cached README\n<span class="token function">git</span> <span class="token function">rm</span> log/<span class="token punctuation">\\</span>*.log\n\n<span class="token function">git</span> <span class="token function">mv</span> README.md README\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>查看提交历史:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> log\n<span class="token function">git</span> log -p -2\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>查看简略信息:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> log --stat\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="remote" tabindex="-1"><a class="header-anchor" href="#remote" aria-hidden="true">#</a> Remote</h2><p>列出远程仓库的简短名称:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> remote\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>显示出Git存储的每个远程仓库对应的 URL:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> remote -v\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>检查远程仓库，列出远程仓库的 url 地址以及每个分支的跟踪信息：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> remote show origin\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>添加一个远程仓库，并给它起一个简短的名称以便于引用:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> remote <span class="token function">add</span> <span class="token punctuation">[</span>shortname<span class="token punctuation">]</span> <span class="token punctuation">[</span>url<span class="token punctuation">]</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>删除远程仓库</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> remote <span class="token function">rm</span> <span class="token operator">&lt;</span>rep-name<span class="token operator">&gt;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>从远程仓库获取和拉取数据:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> fetch <span class="token punctuation">[</span>remote-name<span class="token punctuation">]</span>\n<span class="token comment"># e.g. git fetch pb</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>将变更推送到远程仓库:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> push origin master\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>需要注意的一点是，推送变更时需要拥有远程仓库的写权限，并且克隆后没有任何其他人向远程仓库推送过数据。如果别人和你都clone了这个仓库，而他先推送，你后推送，那么你的这次推送会直接被拒绝。你必须先拉取别人的变更，将其整合到你的工作成果中，然后才能推送。</p><h2 id="git-别名" tabindex="-1"><a class="header-anchor" href="#git-别名" aria-hidden="true">#</a> Git 别名</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> config --global alias.co checkout\n<span class="token function">git</span> config --global alias.br branch\n<span class="token function">git</span> config --global alias.unstage <span class="token string">&#39;reset HEAD --&#39;</span>\n<span class="token comment"># git unstage filaA == git reset HEAD --fileA</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="git-branch" tabindex="-1"><a class="header-anchor" href="#git-branch" aria-hidden="true">#</a> Git Branch</h2><p>分支意味着偏离开发主线并继续你自己的工作而不影响主线开发，分支机制是Git的“杀手锏”！</p><p>当你创建一个新分支的时候会发生什么？实际上，Git会创建一个可移动的新指针供你使用。</p><p>创建分支:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> branch testing\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>列出所有分支:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> branch\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>切换分支:</p><p><code>checkout</code> 命令会改变 HEAD 指针，使其指向 testing 分支，在 Gi t中，HEAD 是一个指向当前所在的本地分支的指针</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> checkout testing\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>分支与合并, 创建并切换到该分支，一般使用这个快速创建分支：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> checkout -b testing\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>切换回master分支:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> checkout master\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>合并分支:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> merge testing\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>删除分支:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> branch -d testing\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>注意到在merge的时候会有提示&quot;fast-forward&quot;，这由于当前的master分支所指向的提交是要并入的testing分支的直接上游，因为Git会将master分支指针向前移动。</p><p>合并冲突处理，配置合并工具：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> config merge.tool vimdiff\n<span class="token function">git</span> config merge.conflictstyle <span class="token function">diff3</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="分支管理" tabindex="-1"><a class="header-anchor" href="#分支管理" aria-hidden="true">#</a> 分支管理</h3><p>查看每个分支上的最新提交:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> branch -v\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查看哪些分支已经合并入当前分支的:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> branch --merged\n<span class="token function">git</span> branch --no-merged\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>远程分支</p><p>如果从Git服务器clone到本地，Git的 clone 命令会自动把这台服务器命名为 origin，使用<code>git clone -o &lt;yourname&gt;</code>便可以修改远程仓库的默认名称为：your name/master。</p><p>如果你在本地的 master 分支上进行了一些工作，与此同时，别人向 Git 服务器推送了数据，更新了服务器上的 master 分支，这时你的提交历史就与服务器上的历史产生了偏离。</p><p>于是要与服务器同步，下面的命令会查询 origin 对应的服务器地址，并从服务器取得本地尚未包含的数据，然后更新本地数据库，最后把 origin/master 指针移动到最新的位置上去。</p><p>与服务器同步:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> fetch origin\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>与其他人共享serverfix分支:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> push origin serverfix\n<span class="token function">git</span> push <span class="token punctuation">(</span>remote<span class="token punctuation">)</span> <span class="token punctuation">(</span>branch<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>等价于下述代码的省略形式:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> push origin serverfix:serverfix\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>第一个为本地分支名，第二个为远程分支名，可把远程分支重命名</p><p>跟踪分支</p><p>当你克隆一个远程仓库时，Git默认情况下会自动地创建跟踪这远程origin/master分支的本地master分支。除此之外，你也可是设置成不跟踪master分支。</p><p><code>git checkout --track origin/serverfix</code></p><p>或者<code>git checkout -b sf origin/serverfix</code></p><p>完成上述命令以后，你的本地sf就会从origin/server上获取数据。</p><p>拉取</p><p><code>git fetch</code>命令会拉取本地没有的远程最新更改数据，但它只会从服务器上拉取数据，然后让你自己进行合并。</p><p><code>git pull</code>命令在大多数情况下基本等同于执行<code>git fetch</code>之后紧跟着执行了<code>git merge</code>命令。</p><p>一般来说，显示地直接使用fetch和merge命令比使用git pull要更好，因为git pull的机制常常使人迷惑。</p><p>删除远程服务器上的master分支:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> push origin --delete serverfix\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>上述操作只是删除了远程服务器上的分支指针，Git会保留数据一段时间知道下一次触发垃圾回收。</p><h2 id="reference" tabindex="-1"><a class="header-anchor" href="#reference" aria-hidden="true">#</a> Reference</h2><hr class="footnotes-sep">',79),C={class:"footnotes"},U={class:"footnotes-list"},A={id:"footnote1",class:"footnote-item"},T={href:"https://source.android.com/setup/create/coding-tasks",target:"_blank",rel:"noopener noreferrer"},D=(0,a.Uk)("Source Control Workflow"),W=(0,a.Uk)(" [^2 ]: "),O={href:"https://source.android.com/setup/develop/repo#init",target:"_blank",rel:"noopener noreferrer"},M=(0,a.Uk)("Repo 命令参考资料"),N=(0,a.Uk)(),q=(0,a._)("a",{href:"#footnote-ref1",class:"footnote-backref"},"↩︎",-1),P={},z=(0,n(3744).Z)(P,[["render",function(e,s){const n=(0,a.up)("ExternalLinkIcon");return(0,a.wg)(),(0,a.iD)("div",null,[i,t,(0,a._)("p",null,[l,(0,a._)("a",d,[c,(0,a.Wm)(n)])]),r,(0,a._)("div",o,[p,u,g,(0,a._)("p",null,[h,(0,a._)("a",v,[m,(0,a.Wm)(n)])]),b]),f,(0,a._)("ol",null,[k,(0,a._)("li",null,[(0,a._)("p",null,[x,(0,a._)("a",_,[w,(0,a.Wm)(n)])])]),G]),R,(0,a._)("p",null,[y,(0,a._)("a",H,[E,(0,a.Wm)(n)])]),S,(0,a._)("section",C,[(0,a._)("ol",U,[(0,a._)("li",A,[(0,a._)("p",null,[(0,a._)("a",T,[D,(0,a.Wm)(n)]),W,(0,a._)("a",O,[M,(0,a.Wm)(n)]),N,q])])])])])}]])},3744:(e,s)=>{s.Z=(e,s)=>{const n=e.__vccOpts||e;for(const[e,a]of s)n[e]=a;return n}}}]);